Looking at a typical OpIterator implementation for Quill Delta:

```javascript
next(length?: number): Op {
  if (!length) {
    length = Infinity;
  }
  const nextOp = this.ops[this.index];
  if (nextOp) {
    const offset = this.offset;
    const opLength = Op.length(nextOp);
    if (length >= opLength - offset) {
      length = opLength - offset;
      this.index += 1;
      this.offset = 0;
    } else {
      this.offset += length;
    }
    if (typeof nextOp.delete === 'number') {
      return { delete: length };
    }
    const retOp: Op = {};
    if (nextOp.attributes) {
      retOp.attributes = nextOp.attributes;
    }
    if (nextOp.retain) {
      retOp.retain = typeof nextOp.retain === 'number' ? length : nextOp.retain;
    } else {
      retOp.insert =
        typeof nextOp.insert === 'string'
          ? nextOp.insert.substr(offset, length)
          : nextOp.insert;
    }
    return retOp;
  }
  return { retain: Infinity };
}
```

